 31	const useProgressNow = (active: boolean, now?: number): number => {
 32	  const [currentNow, setCurrentNow] = useState(() => now ?? Date.now());
 33	
 34	  useEffect(() => {
 35	    if (now !== undefined) {
 36	      setCurrentNow(now);
 37	      return undefined;
 38	    }
 39	    if (!active) {
 40	      setCurrentNow(Date.now());
 41	      return undefined;
 42	    }
 43	    const interval = window.setInterval(() => setCurrentNow(Date.now()), 1000);
 44	    return () => window.clearInterval(interval);
 45	  }, [active, now]);
 46	
 47	  return now ?? currentNow;
 48	};
