 30	const pad2 = (value: number): string => String(value).padStart(2, "0");
 31	
 32	const timestampMs = (timestamp?: string | null): number | null => {
 33	  if (!timestamp) return null;
 34	  const parsed = Date.parse(timestamp);
 35	  return Number.isNaN(parsed) ? null : parsed;
 36	};
