 92	export const agentEventLabel = (event: RendererRunEvent): string => {
 93	  switch (event.type) {
 94	    case "run.started":
 95	    case "run.completed":
 96	    case "run.failed":
 97	      return "Run";
 98	    case "agent.message.delta":
 99	    case "agent.message.completed":
100	      return "Message";
101	    case "command.started":
102	    case "command.output":
103	    case "command.completed":
104	      return "Command";
105	    case "file.change":
106	      return "File";
107	    case "web.search":
108	      return "Web Search";
109	    case "approval.requested":
110	    case "approval.resolved":
111	      return "Approval";
112	    case "ticket.status_changed":
113	      return "Status";
114	    case "clarification.requested":
115	      return "Clarification";
116	    default:
117	      return "Event";
118	  }
