121	export const agentEventTone = (event: RendererRunEvent): "neutral" | "success" | "warning" | "danger" | "info" => {
122	  if (event.type === "run.failed" || (event.type === "command.completed" && event.status === "failed")) return "danger";
123	  if (event.type === "run.completed" || (event.type === "command.completed" && event.status === "completed")) return "success";
124	  if (event.type === "clarification.requested" || event.type === "approval.requested") return "warning";
125	  if (event.type === "web.search" || event.type === "file.change" || event.type === "ticket.status_changed") return "info";
126	  return "neutral";
127	};
128	
129	export const sortAgentEvents = (events: RendererRunEvent[]): RendererRunEvent[] =>
130	  events
131	    .map((event, index) => ({ event, index }))
132	    .sort((a, b) => eventTime(a.event) - eventTime(b.event) || a.index - b.index)
133	    .map(({ event }) => event);
134	
135	export const mergeRunEvents = (...eventGroups: RendererRunEvent[][]): RendererRunEvent[] => {
136	  const merged = new Map<string, RendererRunEvent>();
137	  for (const event of eventGroups.flat()) {
138	    const key = `${event.runId}|${event.timestamp}|${event.type}|${agentEventText(event)}`;
139	    if (!merged.has(key)) merged.set(key, event);
140	  }
141	  return sortAgentEvents([...merged.values()]);
142	};
143	
144	const statusCopy = (
145	  status: AgentProgressStatus
146	): Pick<AgentProgressMetrics, "statusLabel" | "statusDetail" | "statusTone"> => {
147	  switch (status) {
148	    case "drafting":
149	      return { statusLabel: "Drafting", statusDetail: "Codex is preparing a ticket draft.", statusTone: "active" };
150	    case "running":
151	      return { statusLabel: "Active", statusDetail: "Codex is working on this ticket.", statusTone: "active" };
152	    case "blocked":
153	      return { statusLabel: "Needs input", statusDetail: "Codex is waiting on clarification.", statusTone: "warning" };
154	    case "failed":
155	      return { statusLabel: "Failed", statusDetail: "The agent session ended with an error.", statusTone: "danger" };
156	    case "completed":
157	      return { statusLabel: "Completed", statusDetail: "The latest agent session has finished.", statusTone: "success" };
158	    case "cancelled":
159	      return { statusLabel: "Cancelled", statusDetail: "The latest agent session was stopped.", statusTone: "danger" };
160	    case "idle":
161	    default:
162	      return { statusLabel: "Inactive", statusDetail: "No agent session is currently active.", statusTone: "idle" };
163	  }
164	};
165	
166	export const deriveAgentProgress = ({
167	  events,
168	  status,
169	  startedAt,
170	  endedAt,
171	  now = Date.now(),
172	  metricsAvailable
173	}: AgentProgressInput): AgentProgressMetrics => {
174	  const sorted = sortAgentEvents(events);
175	  const active = isAgentSessionActive(status);
176	  const firstEvent = sorted[0] ?? null;
177	  const lastEvent = sorted.at(-1) ?? null;
178	  const runStarted = sorted.find((event) => event.type === "run.started") ?? null;
179	  const terminalEvent =
180	    [...sorted].reverse().find((event) => event.type === "run.completed" || event.type === "run.failed" || event.type === "clarification.requested") ??
181	    null;
182	
183	  const effectiveStartedAt = startedAt ?? runStarted?.timestamp ?? firstEvent?.timestamp ?? null;
184	  const effectiveEndedAt = endedAt ?? (active ? null : terminalEvent?.timestamp ?? lastEvent?.timestamp ?? null);
185	  const startMs = timestampMs(effectiveStartedAt);
186	  const endMs = active ? now : timestampMs(effectiveEndedAt);
187	  const elapsedMs = startMs !== null && endMs !== null ? Math.max(0, endMs - startMs) : null;
188	  const haveMetrics = metricsAvailable ?? sorted.length > 0;
189	  const filesEdited = haveMetrics ? new Set(sorted.filter((event) => event.type === "file.change").map((event) => event.path)).size : null;
190	  const webSearches = haveMetrics ? sorted.filter(isWebSearchEvent).length : null;
191	
192	  return {
193	    ...statusCopy(status),
194	    active,
195	    elapsedMs,
196	    elapsedLabel: formatElapsedDuration(elapsedMs),
197	    filesEdited,
198	    webSearches,
199	    totalEvents: sorted.length,
200	    startedAt: effectiveStartedAt,
201	    endedAt: effectiveEndedAt,
202	    lastEventAt: lastEvent?.timestamp ?? null,
203	    metricsAvailable: haveMetrics
204	  };
205	};
